// ════════════════════════════════════════════════════════
// TOOL: SALVAR CLIENTE (Cadastro Rápido)
// Cadastra novo cliente via WhatsApp
// Padrão: clienteRapido = true
// ════════════════════════════════════════════════════════

const input = $input.item.json;
const query = input.query || '';
const organizacaoId = input.organizacao_id || input.organizacaoId;
const telefoneLimpo = input.telefone_limpo || input.telefone || '';
const remoteJid = input.remote_jid || input.remetente_numero || '';

// Extrair nome do query
let nome = input.nome || '';
if (!nome && query) {
  // O agente deve passar o nome no query
  nome = query.trim();
}

// Extrair telefone
let telefone = telefoneLimpo;
if (!telefone && remoteJid) {
  telefone = remoteJid.replace('@s.whatsapp.net', '').replace('@c.us', '');
}

if (!nome) {
  return [{ json: { error: true, message: 'Nome do cliente não informado.' } }];
}
if (!telefone) {
  return [{ json: { error: true, message: 'Telefone do cliente não informado.' } }];
}
if (!organizacaoId) {
  return [{ json: { error: true, message: 'organizacao_id não informado.' } }];
}

// Gerar username e password no padrão clienteRapido
const codigo6Digitos = String(Math.floor(100000 + Math.random() * 900000));
const username = 'cliente_rapido_' + codigo6Digitos;
const passwordPlain = 'cliente_rapido';

return [{
  json: {
    nome: nome,
    telefone: telefone,
    organizacao_id: organizacaoId,
    username: username,
    password_plain: passwordPlain
  }
}];

// Verificar se cliente já existe
const resultado = $input.item.json;
const dadosCliente = $('Extrair Parâmetros').item.json;

if (resultado && resultado.id) {
  return [{
    json: {
      duplicado: true,
      cliente_id: resultado.id,
      ...dadosCliente
    }
  }];
}

return [{
  json: {
    duplicado: false,
    ...dadosCliente
  }
}];

// Cliente já existe - retornar dados existentes
const dados = $input.item.json;
return [{
  json: {
    response: JSON.stringify({
      sucesso: false,
      mensagem: 'Este telefone já está cadastrado.',
      cliente_id: dados.cliente_id
    }),
    success: false
  }
}];

// Formatar resposta de sucesso
const resultado = $input.item.json;

if (resultado && resultado.cliente_id) {
  return [{
    json: {
      response: JSON.stringify({
        sucesso: true,
        cliente_id: resultado.cliente_id,
        nome: resultado.nome,
        mensagem: 'Cliente cadastrado com sucesso!'
      }),
      success: true
    }
  }];
} else {
  return [{
    json: {
      response: JSON.stringify({
        sucesso: false,
        mensagem: 'Erro ao cadastrar cliente. Tente novamente.'
      }),
      success: false
    }
  }];
}
